import uuid
import hashlib
from threading import Lock

class PiiVault:
    """
    In-process vault for pseudonymisation.
    In production: back this with an encrypted database table or HashiCorp Vault.
    """
    def __init__(self):
        self._lock = Lock()
        # value → token
        self._forward: dict[tuple[str, str], str] = {}
        # token → (pii_type, value)
        self._reverse: dict[str, tuple[str, str]] = {}

    def tokenize(self, pii_type: str, value: str) -> str:
        key = (pii_type, value)
        with self._lock:
            if key not in self._forward:
                # Deterministic prefix + random suffix for readability
                prefix = pii_type[:3].upper()  # EMA, PER, PHO, etc.
                suffix = uuid.uuid4().hex[:8]
                token = f"{prefix}_{suffix}"
                self._forward[key] = token
                self._reverse[token] = (pii_type, value)
            return self._forward[key]

    def dereference(self, token: str) -> tuple[str, str] | None:
        """Requires explicit authorization check in production before calling."""
        return self._reverse.get(token)


vault = PiiVault()


from presidio_anonymizer.entities import OperatorConfig
from typing import Callable

def _make_tokenize_op(pii_type: str) -> OperatorConfig:
    """Return a custom Presidio operator that tokenizes via the vault."""
    class TokenizeOperator:
        def operate(self, text: str, params: dict) -> str:
            return vault.tokenize(pii_type, text)

        def validate(self, params: dict) -> None:
            pass

        def operator_name(self) -> str:
            return "tokenize"

    return OperatorConfig("custom", {"lambda": lambda x: vault.tokenize(pii_type, x)})


def tokenize_redact(text: str) -> str:
    results = analyzer.analyze(text=text, entities=ENTITIES, language="en")
    if not results:
        return text
    operators = {
        entity: OperatorConfig("custom", {"lambda": lambda x, e=entity: vault.tokenize(e, x)})
        for entity in ENTITIES
    }
    operators["DEFAULT"] = OperatorConfig("custom", {"lambda": lambda x: vault.tokenize("OTHER", x)})
    return anonymizer.anonymize(text=text, analyzer_results=results, operators=operators).text


# Example: same email → same token across calls
print(tokenize_redact("Email alice@corp.com for details."))
# → "Email EMA_3c8f12a1 for details."
print(tokenize_redact("Also CC alice@corp.com."))
# → "Also CC EMA_3c8f12a1."  (same token — consistent across the session)

import json
import re

# Fields that always contain PII regardless of value
SENSITIVE_KEYS = {
    "email", "to", "from", "cc", "bcc",
    "phone", "address", "name", "full_name",
    "ssn", "dob", "date_of_birth", "credit_card",
}

# Fields that may contain PII (scan with regex/NER)
SCAN_KEYS = {"message", "body", "content", "text", "note", "description"}


def redact_json_for_log(obj, depth: int = 0) -> object:
    """Recursively redact a parsed JSON object for safe logging."""
    if depth > 10:  # protect against deeply nested or circular structures
        return "[TOO_DEEP]"

    if isinstance(obj, dict):
        return {
            k: (
                "[REDACTED]" if k.lower() in SENSITIVE_KEYS
                else label_redact(str(v)) if k.lower() in SCAN_KEYS and isinstance(v, str)
                else redact_json_for_log(v, depth + 1)
            )
            for k, v in obj.items()
        }
    elif isinstance(obj, list):
        return [redact_json_for_log(item, depth + 1) for item in obj]
    elif isinstance(obj, str):
        # Scan free-form string values for PII
        return label_redact(obj) if len(obj) > 10 else obj
    else:
        return obj  # int, float, bool, None — safe as-is


def redact_tool_call_for_log(tool_call: dict) -> dict:
    """Redact a single OpenAI tool_call object."""
    try:
        args = json.loads(tool_call.get("function", {}).get("arguments", "{}"))
        safe_args = redact_json_for_log(args)
    except json.JSONDecodeError:
        safe_args = {"_parse_error": "[REDACTED_MALFORMED_JSON]"}

    return {
        "id": tool_call.get("id", ""),
        "type": tool_call.get("type", ""),
        "function": {
            "name": tool_call.get("function", {}).get("name", ""),
            "arguments": json.dumps(safe_args),
        },
    }


# Example
tool_call_raw = {
    "id": "call_abc123",
    "type": "function",
    "function": {
        "name": "send_email",
        "arguments": json.dumps({
            "to": "alice@corp.com",
            "subject": "Follow-up",
            "body": "Hi Alice, regarding your account 4532-1234-5678-9010...",
        })
    }
}
safe = redact_tool_call_for_log(tool_call_raw)
print(json.dumps(json.loads(safe["function"]["arguments"]), indent=2))
